import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';
import { FormsModule } from '@angular/forms';
import { CommonModule } from '@angular/common';

import { AppComponent } from './app.component';
// 1. استيراد المكون مرة واحدة فقط بالمسار الصحيح تبعا لمشروعك
import { AppointmentComponent } from './features/appointment/appointment.component'; 

@NgModule({
  declarations: [
    AppComponent
    // ❌ تم حذف AppointmentComponent من هنا لأنه Standalone ولا يجوز عمل declare له
  ],
  imports: [
    BrowserModule,
    FormsModule,
    CommonModule,
    // 2. نقوم بوضعه هنا داخل الـ imports لأنه مكون مستقل Standalone
    AppointmentComponent 
  ],
  providers: [],
  bootstrap: [AppComponent]
})
export class AppModule { }
